INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05240', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'essay', '某少年安置機構驚傳集體性侵害事件。您是該機構主責社工，被授權
進行「危機管理（crisis  management）」。請分就「危機管理」的意
義、目的、與操作過程，對此一事件當如何處理，進行析論。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05241', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '韋恩博（Weinbach）強調社會工作者都是管理者，從事直接服務不但需要運用個案管理與團 隊管理的知能，從事行政、方案、社區等間接服務時，更需要各種管理知識，下列說明何者 正確？', '["管理是管理者的工作", "管理與服務是兩回事", "管理不只是處理事情", "管理要掌握絕對的權力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05242', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者在組織中指導他人活動，必須擁有持續改善組織的各種技能，包括技術性技能 （technical skill）、概念性技能（conceptual skill）、人群關係技能（human relationship skill）、 政治性技能（political skill）。不同管理層級者會具備不同的技能，下列敘述何者錯誤？', '["對督導者、中階管理者、高階管理者而言，人群關係技能是同等重要", "隨著管理階層的提高，技術性技能的重要性隨著增加，高階管理者較常直接涉入技術性的 操作問題與活動", "概念性技能指分析與診斷複雜情境的心智能力，可將之運用於特定情境", "具有良好政治性技能的管理者，能為其團體取得較佳的資源，也可能獲得較佳的評價及較 多的升遷機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05243', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '將管理理論應用於社會工作時，下列敘述何者正確？', '["古典管理學派易使服務機構出現「訓練無能」（trained incompetence）的現象", "運用人群關係學派的服務機構會強烈表現出對責信（accountability）的要求", "系統理論最適用於處理複雜社會問題的服務機構", "權變理論由整體觀點看待管理，有助於服務機構將有限的資源發揮最大的效用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05244', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人群關係學派強調人際關係的運作，認為人不僅為組織工作，而且他們就是組織本身，下列 敘述何者錯誤？', '["X理論假定人本來就是懶散、不負責、抗拒的，而非其工作的組織將之塑造成如此", "Y理論假定人本來就會努力投入工作，贏取自身的成就，學習新的知識，並以此成就為榮", "Z理論在於組織表現出對員工的忠誠，決策是經由共識產生，著重他們共同的關切與承諾", "霍桑（Hawthorne）工廠的研究發現績效與獎勵是提高生產力的預測因素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05245', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新管理主義重視管理優於專業，讓社會工作專業在勞動市場面臨重大挑戰，新管理主義對社 會工作的影響，下列敘述何者錯誤？', '["社工員是組織中最重要的角色，常藉由刪減預算來降低成本", "契約的使用令以往著重於守門者角色的傳統服務輸送，轉而著重使用者的需求導向發展", "管理知識是知識的支配模式，管理技術已成為行動的原則", "效率成為測量組織績效的判準，引用準市場（quasi-market）與購買式服務的作法來扶植競爭"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05246', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '標竿管理（benchmarking）即向成功的組織學習管理的規劃，找出理想的運作模式，作為提 升組織效能的學習標竿，下列何者不是標竿管理的具體技巧？', '["最佳示範作法（best demonstrated practice）", "最佳相關作法（best related practice）", "最佳評估作法（best evaluative practice）", "相對成本位置（relative cost position）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05247', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織（non-profit organization）常以服務大眾為宗旨，具有公益（philanthropy）的特徵， 由社會大眾捐助和使用社會公器（public entity）的性格，下列何者不是非營利組織的特質？', '["市場失靈（market failure）常被用來解釋非營利組織存在的原因", "非營利組織不以營利為目的，所有的服務與產品皆須免費提供", "非營利組織享有優稅待遇，亦可提供捐助者減（免）稅的合法地位", "非營利組織具有不分配盈餘的特性，較能獲得民眾的信任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05248', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「知識管理」是管理觀念的新思維，此理論相當強調在組織中建構知識轉化的系統，以使外 顯知識（explicit knowledge）與內隱知識（tacit knowledge）可以在部門間轉換，意即若管理 者能善用知識，即可強化組織的服務能力。日本知識管理專家野中郁次郎（Ikujiro Nonaka） 即提出SECI模型。下列對於此模型知識轉化的描述，何者正確？', '["透過座談會的方式使員工有機會可以針對一個議題進行討論與對話，此是「融合」 （combination）", "將資深員工的工作經驗與技巧整理成文字與書面資料，此是「社會化」（socialization）", "新進員工藉由閱讀組織內的文件、檔案、紀錄等等來增加自己對於工作的了解，此是「內 化」（internalization）", "一個以服務兒少為主的機構邀請員工撰寫相關主題論文，並辦理研討會交流，後續更出版 論文集，此為「外化」（externalization）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05249', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '目標管理（Management by Objective, MBO）強調管理者以「工作目標」來管理部屬，因此 由管理者與部屬共同設定明確的目標，即是組織進行目標導向之績效管理的首要步驟，具體 執行上則需要將目標轉化為「績效指標」（performance indicator）與「績效標準」（performance standard）。下列對於「績效指標」與「績效標準」的描述，何者錯誤？', '["績效標準是指所提供的服務之可被接受的最低層次，需符合機構任務的執行，且要能夠由 績效指標予以測量", "績效指標是衡量服務能否達到經濟、效率與品質的重要工具", "社會服務機構常採用的績效指標之一為「目標達成指標」，是以組織預先擬定之目標作為 績效衡量基準，例如：每月電訪需達30人次以上", "「SEA（service efforts and accomplishment）指標」是社會服務機構常採用的績效指標之一， 可再分為：投入產出比率的努力指標、投入面的成就指標以及產出面的效率指標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
